fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let original_profit: i64 = strategy.iter().zip(prices.iter()).map(|(&s, &p)| s * p).sum();
    let k = k as usize;
    let half = k / 2;
    let mut prefix_sum = vec![0; n + 1];
    let mut price_prefix = vec![0; n + 1];
    for i in 0..n {
        prefix_sum[i + 1] = prefix_sum[i] + strategy[i] * prices[i];
        price_prefix[i + 1] = price_prefix[i] + prices[i];
    }
    let mut max_delta = 0;
    for i in 0..=n - k {
        let first_half_end = i + half;
        let second_half_start = first_half_end;
        let second_half_end = i + k;
        let sum_first = prefix_sum[first_half_end] - prefix_sum[i];
        let sum_second = prefix_sum[second_half_end] - prefix_sum[second_half_start];
        let sum_second_prices = price_prefix[second_half_end] - price_prefix[second_half_start];
        let delta = (sum_second_prices - sum_second) - sum_first;
        if delta > max_delta {
            max_delta = delta;
        }
    }
    original_profit + max_delta.max(0)
}
